-- QUALIFIED IMMUNITY / § 1983 (ADVOCIS)
-- ═══════════════════════════════════════════════════════════════════════════

-- Harlow v. Fitzgerald — Qualified Immunity Objective Test
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_035', 'ADVOCIS', 'CASE_LAW', 'US', 'Harlow v. Fitzgerald, 457 U.S. 800 (1982)', 'Harlow v. Fitzgerald', 'Qualified Immunity — Objective Legal Reasonableness Standard', 'Replaced subjective good-faith immunity test with objective standard. Government officials performing discretionary functions are shielded from liability for civil damages insofar as their conduct does not violate clearly established statutory or constitutional rights of which a reasonable person would have known. Eliminated subjective component (good faith/malice inquiry) because it created factual disputes defeating summary judgment. QI protects "all but the plainly incompetent or those who knowingly violate the law."', '["Objective test: did conduct violate clearly established law at time of action","Eliminated subjective good-faith inquiry from QI analysis","Clearly established means contours of right sufficiently clear that reasonable official would understand conduct violates it","Officials performing discretionary functions receive QI","QI is immunity from suit, not merely defense to liability","QI question should be resolved at earliest possible stage — summary judgment","Burden on plaintiff to show right was clearly established","Protects all but plainly incompetent or knowing violators"]', '[{"section":"Holding","description":"QI turns on objective legal reasonableness under clearly established law, not subjective intent"},{"section":"Standard","description":"Would a reasonable official understand that conduct violated clearly established right"},{"section":"Procedure","description":"QI resolved at summary judgment — immunity from suit not just liability"},{"section":"Impact","description":"Foundation of modern qualified immunity doctrine — two-step Saucier analysis built on this"}]', '["qualified_immunity_motion","summary_judgment_motion","1983_complaint","clearly_established_law_brief","interlocutory_appeal"]', '["victim-rights-marsys-law-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Hope v. Pelzer — Obvious Clarity Standard
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_036', 'ADVOCIS', 'CASE_LAW', 'US', 'Hope v. Pelzer, 536 U.S. 730 (2002)', 'Hope v. Pelzer', 'Qualified Immunity — Obvious Clarity Without Materially Similar Facts', 'Plaintiff need not identify a case with materially similar facts to overcome qualified immunity. General constitutional principles can clearly establish a right when the unlawfulness of the conduct is apparent from pre-existing law. Handcuffing inmate to hitching post in the sun for seven hours was obviously unconstitutional under Eighth Amendment even without case with identical facts. Officials can be on notice that their conduct is unlawful even in novel factual circumstances.', '["No requirement of prior case with materially similar facts to defeat QI","General statements of law can clearly establish right in obvious cases","Obvious clarity: conduct so egregious that any reasonable officer would know it violated Constitution","Officials on notice their conduct violates established law even in novel circumstances","Eighth Amendment cruel and unusual punishment standard applied","Broad hope of law — not just narrow factual precedent — determines clearly established","Rejects rigid requirement of factually identical prior case"]', '[{"section":"Holding","description":"Materially similar prior case not required — general constitutional principles can clearly establish right"},{"section":"Obvious Clarity","description":"When unlawfulness is apparent from pre-existing law, specific factual precedent unnecessary"},{"section":"Application","description":"Hitching post punishment obviously cruel and unusual without identical prior case"},{"section":"Impact","description":"Limits ability of officials to claim QI in cases of obvious constitutional violation"}]', '["qualified_immunity_opposition","clearly_established_law_brief","obvious_clarity_argument","1983_complaint","eighth_amendment_claim"]', '["victim-rights-marsys-law-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- City of Canton v. Harris — Failure to Train
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_037', 'ADVOCIS', 'CASE_LAW', 'US', 'City of Canton v. Harris, 489 U.S. 378 (1989)', 'City of Canton v. Harris', 'Municipal Liability — Failure to Train Under Deliberate Indifference Standard', 'Municipality may be liable under § 1983 for failure to train employees where the failure amounts to deliberate indifference to the rights of persons with whom employees come into contact. Inadequacy of training must be closely related to the ultimate injury. Must show: (1) training program inadequate relative to tasks officers must perform, (2) inadequacy resulted from municipality''s deliberate indifference, (3) inadequacy actually caused the constitutional violation. Single-incident liability possible when need for training is so obvious.', '["Failure to train can be policy or custom for Monell municipal liability","Deliberate indifference: municipality knows of need and disregards it","Training inadequacy must be closely related to constitutional injury","Three elements: inadequate program, deliberate indifference, causation","Pattern of violations normally required to show deliberate indifference","Single-incident liability where need for training is obvious and predictable","Not simple negligence — must rise to deliberate indifference","City must have actual or constructive notice of deficiency"]', '[{"section":"Holding","description":"Municipality liable under § 1983 for failure to train amounting to deliberate indifference"},{"section":"Standard","description":"Deliberate indifference — not negligence — to known training deficiency"},{"section":"Causation","description":"Training inadequacy must be closely related to the constitutional violation"},{"section":"Single Incident","description":"Possible liability from single incident where need for training is obvious"},{"section":"Impact","description":"Established failure-to-train as viable Monell theory — extends Canton to failure to supervise"}]', '["failure_to_train_claim","Monell_claim","deliberate_indifference_evidence","municipal_liability_complaint","pattern_and_practice_evidence","police_training_records_request"]', '["victim-rights-marsys-law-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));


