-- Bell Atlantic Corp. v. Twombly — Plausibility Pleading
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_038', 'ADVOCIS', 'CASE_LAW', 'US', 'Bell Atlantic Corp. v. Twombly, 550 U.S. 544 (2007)', 'Twombly', 'Plausibility Pleading Standard — Retirement of "No Set of Facts" Test', 'Replaced Conley v. Gibson''s "no set of facts" standard with plausibility pleading requirement under FRCP 8(a)(2). Complaint must contain enough factual matter, accepted as true, to state a claim to relief that is plausible on its face. Claim has facial plausibility when plaintiff pleads factual content that allows court to draw reasonable inference that defendant is liable. Allegations must nudge claims across line from conceivable to plausible. Labels, conclusions, and formulaic recitation of elements not sufficient.', '["Plausibility standard replaces Conley no-set-of-facts test","Factual matter must state claim plausible on its face","Court draws reasonable inferences in plaintiff''s favor","Labels, conclusions, formulaic recitation insufficient","Factual content must allow inference of liability","Conceivable is not enough — must be plausible","Applied through Iqbal to all federal civil cases","Two-step analysis: identify conclusory statements, then assess plausibility of remaining facts"]', '[{"section":"Holding","description":"Complaint must state plausible claim — retired Conley no-set-of-facts standard"},{"section":"Plausibility","description":"Facial plausibility when factual content allows reasonable inference of liability"},{"section":"Threshold","description":"Claims must be nudged from conceivable to plausible"},{"section":"Impact","description":"Heightened pleading standard — extended to all civil cases by Ashcroft v. Iqbal (2009)"}]', '["federal_complaint","motion_to_dismiss_12b6","opposition_to_motion_to_dismiss","amended_complaint","plausibility_analysis"]', '["victim-rights-marsys-law-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));


