-- Griswold v. Connecticut — Right to Privacy
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_039', 'ADVOCIS', 'CASE_LAW', 'US', 'Griswold v. Connecticut, 381 U.S. 479 (1965)', 'Griswold v. Connecticut', 'Right to Privacy in Marital Relations — Penumbras of the Bill of Rights', 'Struck down Connecticut law criminalizing use of contraceptives by married couples. Right to privacy found in penumbras and emanations of the First, Third, Fourth, Fifth, and Ninth Amendments. The marital relationship lies within a zone of privacy created by several fundamental constitutional guarantees. Government may not intrude into the sacred precincts of marital bedrooms. Foundation for substantive due process privacy rights expanded in Eisenstadt, Roe, Lawrence, and Obergefell.', '["Right to privacy exists in penumbras of Bill of Rights","First Amendment: right of association and periphery rights","Third Amendment: prohibition on quartering soldiers implies privacy of home","Fourth Amendment: right against unreasonable searches — privacy of persons and effects","Fifth Amendment: self-incrimination clause — zone of privacy","Ninth Amendment: enumerated rights shall not be construed to deny other rights retained by people","Marital relationship within zone of constitutional privacy","State cannot regulate intimate decisions of married couples"]', '[{"section":"Holding","description":"Right to marital privacy found in penumbras and emanations of Bill of Rights"},{"section":"Penumbras","description":"Specific guarantees in Bill of Rights have penumbras formed by emanations giving them life and substance"},{"section":"Zone of Privacy","description":"Marriage lies within zone of privacy created by several constitutional guarantees"},{"section":"Impact","description":"Foundation for modern privacy jurisprudence — Eisenstadt, Roe, Lawrence, Obergefell"}]', '["privacy_rights_motion","due_process_claim","constitutional_challenge","family_privacy_argument","substantive_due_process_brief"]', '["victim-rights-marsys-law-audit"]', 'US Supreme Court', 1, 1, datetime('now'), datetime('now'));

-- Lawrence v. Texas — Liberty and Intimate Conduct
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_040', 'ADVOCIS', 'CASE_LAW', 'US', 'Lawrence v. Texas, 539 U.S. 558 (2003)', 'Lawrence v. Texas', 'Due Process Liberty Protects Intimate Conduct Between Consenting Adults', 'Struck down Texas anti-sodomy statute. Overruled Bowers v. Hardwick (1986). Liberty under the Due Process Clause gives persons the full right to engage in private conduct without government intervention. Adults may choose to enter personal relationships in the confines of their homes and their own private lives and still retain their dignity as free persons. Moral disapproval alone is not a legitimate state interest sufficient to justify intrusion into personal and private life.', '["Liberty under Due Process Clause protects intimate conduct","Overruled Bowers v. Hardwick — liberty interest not limited to those historically recognized","Private consensual conduct between adults is constitutionally protected","Moral disapproval alone not legitimate state interest to justify intrusion","Dignity of free persons includes right to define personal relationships","State cannot demean existence or control destiny by criminalizing private conduct","Not decided on Equal Protection grounds — broader liberty rationale","Petitioners entitled to respect for their private lives"]', '[{"section":"Holding","description":"Due Process liberty protects intimate conduct between consenting adults — overrules Bowers"},{"section":"Liberty Interest","description":"Right to make choices about intimate conduct is a form of liberty protected by Constitution"},{"section":"Moral Disapproval","description":"Moral disapproval alone insufficient state interest to criminalize private conduct"},{"section":"Impact","description":"Foundation for dignity-based liberty jurisprudence — cited in Obergefell and Windsor"}]', '["due_process_liberty_claim","privacy_rights_motion","substantive_due_process_brief","equal_protection_claim","constitutional_challenge"]', '["victim-rights-marsys-law-audit"]', 'US Supreme Court', 1, 1, datetime('now'), datetime('now'));

-- Brown v. Board of Education — Equal Protection
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_041', 'ADVOCIS', 'CASE_LAW', 'US', 'Brown v. Board of Education, 347 U.S. 483 (1954)', 'Brown v. Board of Education', 'Separate But Equal Is Inherently Unequal — Equal Protection Clause', 'Unanimously overruled Plessy v. Ferguson''s "separate but equal" doctrine in public education. Segregation of children in public schools solely on basis of race, even where physical facilities and other tangible factors are equal, deprives children of the minority group of equal educational opportunities. Separate educational facilities are inherently unequal and violate the Equal Protection Clause of the Fourteenth Amendment. Education is the most important function of state and local governments.', '["Separate but equal is inherently unequal in public education","Overruled Plessy v. Ferguson separate but equal doctrine","Segregation solely on race denies equal educational opportunity","Equal Protection Clause of 14th Amendment prohibits racial segregation","Education is most important function of state and local governments","Psychological harm of segregation — generates feeling of inferiority","Cannot turn back clock — must consider public education in light of its full development","Unanimous decision — Warren Court"]', '[{"section":"Holding","description":"Separate educational facilities are inherently unequal — violates Equal Protection"},{"section":"Overruling","description":"Plessy v. Ferguson separate but equal doctrine overruled in public education"},{"section":"Education","description":"Education is perhaps the most important function of state and local governments"},{"section":"Impact","description":"Foundational civil rights decision — catalyst for Civil Rights Movement and desegregation"}]', '["equal_protection_claim","civil_rights_complaint","desegregation_order","14th_amendment_brief","discrimination_claim"]', '["victim-rights-marsys-law-audit"]', 'US Supreme Court', 1, 1, datetime('now'), datetime('now'));

-- Shelley v. Kraemer — State Action Doctrine
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_042', 'ADVOCIS', 'CASE_LAW', 'US', 'Shelley v. Kraemer, 334 U.S. 1 (1948)', 'Shelley v. Kraemer', 'Judicial Enforcement of Restrictive Covenants as State Action — Equal Protection', 'Racially restrictive covenants standing alone do not violate the Fourteenth Amendment because they are private agreements. However, judicial enforcement of racially restrictive covenants constitutes state action violating the Equal Protection Clause. When a state court enforces a discriminatory private agreement, the state has made the discrimination its own act. State action is present whenever the state has become significantly involved in private discrimination.', '["Private racially restrictive covenants alone are not state action","Judicial enforcement of discriminatory covenants IS state action","State court enforcement makes private discrimination the act of the state","14th Amendment Equal Protection applies to state judicial action","State involvement transforms private discrimination into constitutional violation","State cannot enforce private agreements that achieve what state itself cannot constitutionally do","Expands state action doctrine to judicial enforcement","Right to acquire and use property without discrimination"]', '[{"section":"Holding","description":"Judicial enforcement of racially restrictive covenants is state action violating Equal Protection"},{"section":"State Action","description":"Court enforcement transforms private discrimination into state discrimination"},{"section":"Private Covenants","description":"Standing alone they are private — but enforcement converts to state action"},{"section":"Impact","description":"Expanded state action doctrine — courts enforcing discrimination become the discriminator"}]', '["state_action_claim","equal_protection_motion","housing_discrimination_complaint","restrictive_covenant_challenge","14th_amendment_brief"]', '["victim-rights-marsys-law-audit"]', 'US Supreme Court / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- New York Times Co. v. Sullivan — Actual Malice / First Amendment
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_043', 'ADVOCIS', 'CASE_LAW', 'US', 'New York Times Co. v. Sullivan, 376 U.S. 254 (1964)', 'NYT v. Sullivan', 'Actual Malice Standard for Defamation of Public Officials — First Amendment', 'First Amendment requires public official suing for defamation to prove statement was made with actual malice — knowledge that statement was false or reckless disregard of whether it was false or not. Protects uninhibited, robust, and wide-open debate on public issues. Erroneous statements are inevitable in free debate and must be protected to give breathing space to freedoms of expression. Actual malice must be proven by clear and convincing evidence. Extended to public figures by Curtis Publishing v. Butts.', '["Public official must prove actual malice to recover for defamation","Actual malice: knowledge of falsity or reckless disregard of truth","Reckless disregard: subjective awareness of probable falsity","Not mere negligence — must be subjective fault","Clear and convincing evidence standard — not preponderance","First Amendment protects robust debate on public issues","Erroneous statement inevitable in free debate — must be protected","Breathing space needed for freedoms of expression to survive"]', '[{"section":"Holding","description":"Public officials must prove actual malice — knowledge of falsity or reckless disregard — for defamation"},{"section":"Actual Malice","description":"Subjective standard — defendant knew statement was false or had high awareness of probable falsity"},{"section":"Proof Standard","description":"Clear and convincing evidence, not mere preponderance"},{"section":"Impact","description":"Constitutional protection for speech about public officials — extended to public figures"}]', '["defamation_defense","first_amendment_brief","actual_malice_analysis","anti_SLAPP_motion","public_official_defamation_response"]', '["victim-rights-marsys-law-audit"]', 'US Supreme Court / Federal and State Courts', 1, 1, datetime('now'), datetime('now'));


