-- Bostock v. Clayton County — Title VII Sexual Orientation/Transgender
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_044', 'REGULIS', 'CASE_LAW', 'US', 'Bostock v. Clayton County, 590 U.S. 644 (2020)', 'Bostock v. Clayton County', 'Title VII Prohibits Employment Discrimination Based on Sexual Orientation and Transgender Status', 'Title VII''s prohibition on discrimination "because of sex" necessarily encompasses discrimination based on sexual orientation and transgender status. An employer who fires an individual merely for being gay or transgender violates Title VII because it is impossible to discriminate against a person for being gay or transgender without discriminating against that individual based on sex. Textualist analysis: discrimination on these bases necessarily involves consideration of sex — "but for" the employee''s sex, the employer would not have acted differently.', '["Title VII because of sex includes sexual orientation and transgender status","Impossible to discriminate on sexual orientation without considering sex","But-for causation: sex need not be sole or primary cause","Textualist interpretation of statutory language","Employer fires male employee for being attracted to men — but would not fire female employee for same — sex is but-for cause","Applies to all Title VII protections: hiring, firing, terms and conditions","No religious employer exemption addressed in this case","RFRA and First Amendment defenses left open for future cases"]', '[{"section":"Holding","description":"Title VII prohibits employment discrimination based on sexual orientation and transgender status"},{"section":"Textualism","description":"Because of sex necessarily encompasses orientation and gender identity — impossible to separate"},{"section":"But-For Causation","description":"Sex need not be sole cause — if sex was one but-for cause, Title VII is violated"},{"section":"Impact","description":"Extended Title VII protections to LGBTQ+ employees nationwide"}]', '["title_vii_complaint","eeoc_charge","employment_discrimination_claim","wrongful_termination_complaint","lgbtq_discrimination_claim"]', '["california-labor-employment-audit"]', 'EEOC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Burlington Northern v. White — Retaliation Standard
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_045', 'REGULIS', 'CASE_LAW', 'US', 'Burlington Northern & Santa Fe Railway Co. v. White, 548 U.S. 53 (2006)', 'Burlington Northern v. White', 'Title VII Retaliation — Materially Adverse Action Standard Broader Than Discrimination', 'Title VII anti-retaliation provision is not limited to workplace-related or employment-related retaliatory acts. A plaintiff must show employer''s action might have dissuaded a reasonable worker from making or supporting a charge of discrimination. Retaliation standard is broader than substantive discrimination standard — covers any materially adverse action, not just ultimate employment decisions. Context matters — reassignment of duties, schedule changes, or suspensions without pay can constitute actionable retaliation depending on circumstances.', '["Retaliation standard broader than substantive discrimination standard","Materially adverse: would dissuade reasonable worker from making charge","Not limited to employment actions — covers conduct outside workplace","No need to show ultimate employment decision (hiring, firing, demotion)","Context matters — same action may be material in one context but not another","Reassignment, schedule changes, suspension without pay can be retaliatory","Reasonable person standard — objective but context-dependent","Anti-retaliation provision has distinct purpose from anti-discrimination provision"]', '[{"section":"Holding","description":"Retaliation encompasses any materially adverse action that might dissuade reasonable worker from complaining"},{"section":"Broader Standard","description":"Retaliation provision covers more than just workplace employment actions"},{"section":"Context Dependent","description":"Whether action is materially adverse depends on circumstances facing particular employee"},{"section":"Impact","description":"Expanded retaliation claims beyond ultimate employment decisions — significant employee protection"}]', '["retaliation_complaint","eeoc_retaliation_charge","title_vii_retaliation_claim","adverse_action_documentation","whistleblower_retaliation_claim"]', '["california-labor-employment-audit"]', 'EEOC / Federal Courts', 1, 1, datetime('now'), datetime('now'));


