-- Brinker Restaurant Corp. v. Superior Court — Meal Periods
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_046', 'REGULIS', 'CASE_LAW', 'CA', 'Brinker Restaurant Corp. v. Superior Court, 53 Cal.4th 1004 (2012)', 'Brinker v. Superior Court', 'Employer Duty to Provide Meal Period Opportunity — Timing Requirements', 'Employer must provide meal period opportunity but need not ensure employees do no work during the period. First meal period must be provided no later than end of fifth hour of work. Second meal period required no later than end of tenth hour. Employer satisfies obligation by relieving employee of all duty, relinquishing control, permitting reasonable opportunity to take uninterrupted 30-minute break, and not impeding or discouraging employee from doing so. No rolling five-hour requirement for second meal period.', '["Employer must provide meal period — not police actual consumption","First meal period: no later than end of 5th hour of work","Second meal period: no later than end of 10th hour of work","Employer must relieve employee of all duty for meal period","Must relinquish control over employee activities during break","Must permit reasonable opportunity for uninterrupted 30-minute break","Must not impede or discourage employee from taking break","No rolling 5-hour requirement — measured from start of shift for first, from end of first meal for second","Premium pay owed for non-compliant meal periods under Labor Code § 226.7"]', '[{"section":"Holding","description":"Employer must provide meal period opportunity — not ensure no work is performed"},{"section":"Timing - First Meal","description":"No later than end of 5th hour of work"},{"section":"Timing - Second Meal","description":"No later than end of 10th hour of work"},{"section":"Employer Obligation","description":"Relieve of duty, relinquish control, permit opportunity, not impede or discourage"},{"section":"Impact","description":"Definitive CA Supreme Court guidance on meal period obligations — resolved class cert and timing disputes"}]', '["meal_period_audit","wage_hour_complaint","class_action_certification","labor_code_violation_claim","meal_period_waiver","premium_pay_calculation"]', '["california-labor-employment-audit"]', 'CA DLSE / CA Superior Courts', 1, 1, datetime('now'), datetime('now'));

-- Dynamex Operations West v. Superior Court — ABC Test
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_047', 'REGULIS', 'CASE_LAW', 'CA', 'Dynamex Operations West v. Superior Court, 4 Cal.5th 903 (2018)', 'Dynamex', 'ABC Test for Independent Contractor Classification — Adopted by AB 5', 'Adopted ABC test for determining worker classification under California wage orders. Worker is presumed to be employee unless hiring entity demonstrates all three factors: (A) worker is free from control and direction in performance of work, both under contract and in fact; (B) worker performs work outside usual course of hiring entity''s business; (C) worker is customarily engaged in independently established trade, occupation, or business of same nature. Replaced multifactor Borello test for wage order claims. Codified by AB 5 (Lab. Code § 2775).', '["ABC test presumes worker is employee — burden on hiring entity to prove otherwise","A prong: free from control and direction — contract AND in fact","B prong: work outside usual course of hiring entity''s business","C prong: customarily engaged in independently established trade or business","All three prongs must be satisfied or worker is employee","Replaced Borello multifactor test for wage order claims","Codified in Labor Code § 2775 et seq. by AB 5 (2019)","Hiring entity bears burden of proof on all three prongs"]', '[{"section":"Holding","description":"ABC test adopted for worker classification — presumption of employment"},{"section":"A Prong","description":"Free from control and direction in contract and fact"},{"section":"B Prong","description":"Work outside usual course of hiring entity business"},{"section":"C Prong","description":"Customarily engaged in independently established trade or business"},{"section":"Impact","description":"Dramatically changed CA independent contractor law — codified by AB 5 — B prong most difficult to satisfy"}]', '["worker_classification_audit","independent_contractor_agreement","ab5_compliance_review","wage_order_claim","misclassification_complaint","edd_audit_response"]', '["california-labor-employment-audit"]', 'CA DLSE / EDD / CA Courts', 1, 1, datetime('now'), datetime('now'));

-- Iskanian v. CLS Transportation — PAGA Waivers
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_048', 'REGULIS', 'CASE_LAW', 'CA', 'Iskanian v. CLS Transportation, 59 Cal.4th 348 (2014)', 'Iskanian v. CLS Transportation', 'PAGA Claims Not Waivable by Arbitration Agreements — Representative Actions Survive', 'PAGA representative action waivers in pre-dispute arbitration agreements are unenforceable as contrary to California public policy. PAGA claims are law enforcement actions brought on behalf of the state — the employee acts as proxy or agent of the state. Because PAGA claim belongs to the state, employee cannot waive the state''s claim through private agreement. FAA does not preempt California rule invalidating PAGA waivers because PAGA is a qui tam-like action, not a dispute between private parties. Note: partially limited by Viking River Cruises v. Moriana (2022) regarding individual PAGA claims.', '["PAGA representative action waivers unenforceable","PAGA is law enforcement action — employee acts as state''s proxy","Employee cannot waive state''s claim through private arbitration agreement","FAA does not preempt — PAGA is not private dispute between parties","PAGA claim belongs to state of California — not the individual employee","Public policy prevents private waiver of state enforcement mechanism","Qui tam-like nature of PAGA distinguishes from private arbitration","Viking River Cruises (2022) later held individual PAGA claims may be compelled to arbitration","Standing PAGA representative claims survive even after Viking River"]', '[{"section":"Holding","description":"PAGA waivers in arbitration agreements are unenforceable — employee acts as state proxy"},{"section":"State Action","description":"PAGA is qui tam-like — employee enforces state labor law as state agent"},{"section":"FAA Preemption","description":"FAA does not preempt because PAGA is not private dispute"},{"section":"Impact","description":"Preserved PAGA as enforcement tool — partially limited by Viking River Cruises v. Moriana (2022) on individual claims"}]', '["paga_complaint","arbitration_agreement_review","paga_waiver_challenge","class_action_arbitration_motion","representative_paga_action","labor_code_violation_paga"]', '["california-labor-employment-audit"]', 'CA LWDA / CA Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- FINANCIAL / STANDING (FISCARA)
-- ═══════════════════════════════════════════════════════════════════════════

-- Spokeo v. Robins — Article III Standing / Concrete Injury
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_049', 'FISCARA', 'CASE_LAW', 'US', 'Spokeo, Inc. v. Robins, 578 U.S. 330 (2016)', 'Spokeo v. Robins', 'Article III Standing — Concrete Injury Required Beyond Bare Statutory Violation', 'Article III standing requires plaintiff to show injury in fact that is (1) concrete, (2) particularized, and (3) actual or imminent. Concreteness is distinct from particularization. A bare procedural violation of a statute, divorced from any concrete harm, does not satisfy Article III injury-in-fact requirement. However, intangible injuries can be concrete — Congress''s judgment in creating statutory right is instructive. Risk of real harm can satisfy concreteness. Not every statutory violation automatically creates standing.', '["Article III standing requires concrete and particularized injury in fact","Concrete and particularized are distinct requirements","Bare procedural statutory violation alone may not confer standing","Intangible injuries can be concrete — not limited to tangible harm","Congress''s judgment in creating statutory right is relevant but not dispositive","Risk of real harm can satisfy concreteness requirement","Historical practice of recognizing injury type informs analysis","Dissemination of false information may constitute concrete harm"]', '[{"section":"Holding","description":"Bare statutory violation without concrete harm does not satisfy Article III standing"},{"section":"Concreteness","description":"Injury must be real, not abstract — distinct from particularization requirement"},{"section":"Intangible Injuries","description":"Can be concrete if historically recognized or Congress elevated to legally cognizable"},{"section":"Impact","description":"Gateway for standing challenges in statutory violation cases — refined by TransUnion v. Ramirez"}]', '["standing_motion","motion_to_dismiss_standing","article_iii_standing_brief","statutory_violation_complaint","concrete_injury_analysis"]', '["banking-financial-document-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- TransUnion LLC v. Ramirez — Standing Refined
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_050', 'FISCARA', 'CASE_LAW', 'US', 'TransUnion LLC v. Ramirez, 594 U.S. 413 (2021)', 'TransUnion v. Ramirez', 'Refined Spokeo — No Standing Without Concrete Harm From Statutory Violation', 'Refined Spokeo''s concrete injury requirement. Only 1,853 of 8,185 class members had standing because only their inaccurate credit files were disseminated to third parties. Remaining class members with inaccurate internal files but no dissemination suffered no concrete harm. Central question: whether plaintiffs have suffered harm with close relationship to harm traditionally recognized as providing basis for lawsuit. No concrete harm = no Article III standing, regardless of statutory violation. Congress cannot manufacture standing by granting right to sue without real injury.', '["Concrete harm required — internal statutory violation without dissemination insufficient","Close relationship to traditionally recognized harms required","Only class members with third-party dissemination had standing","Internal inaccuracy alone without external publication not concrete harm","Congress cannot manufacture Article III standing by creating right to sue","Reputational harm requires publication to third party — parallel to defamation","Risk of future harm must be sufficiently imminent — not speculative","Article III standing assessed member by member in class actions"]', '[{"section":"Holding","description":"Class members without third-party dissemination of inaccurate files lacked Article III standing"},{"section":"Concrete Harm Test","description":"Close relationship to harm traditionally recognized as basis for lawsuit"},{"section":"Congressional Power","description":"Congress cannot confer Article III standing by statute alone — injury must be concrete"},{"section":"Class Actions","description":"Standing must be assessed member by member"},{"section":"Impact","description":"Major limitation on statutory damages class actions — particularly FCRA, TCPA, privacy statutes"}]', '["standing_challenge","class_certification_opposition","article_iii_standing_motion","fcra_standing_analysis","concrete_harm_evidence","class_member_standing_analysis"]', '["banking-financial-document-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- PRIVACY / TECHNOLOGY (PRIVAXIS)
-- ═══════════════════════════════════════════════════════════════════════════

-- Rosenbach v. Six Flags — BIPA Standing
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_051', 'PRIVAXIS', 'CASE_LAW', 'IL', 'Rosenbach v. Six Flags Entertainment Corp., 2019 IL 123186 (Ill. 2019)', 'Rosenbach v. Six Flags', 'BIPA Standing — No Actual Injury Required for Statutory Violation', 'Under Illinois Biometric Information Privacy Act (BIPA), a person "aggrieved" by a violation need not allege actual injury or adverse effect beyond the statutory violation itself. The violation of the statutory right is itself sufficient injury. BIPA''s protections are preventive and prophylactic — actual injury requirement would undermine BIPA''s purpose. When private entity collects biometric data without informed consent, the harm to individual''s right to privacy is real and significant. Contrasts with federal standing under Spokeo/TransUnion.', '["BIPA violation itself confers standing — no actual injury required","Aggrieved person includes anyone whose rights under BIPA are violated","BIPA protections are preventive and prophylactic in nature","Actual injury requirement would undermine legislative purpose","Collection without consent is itself real and significant harm","Private right of action explicitly created by BIPA § 20","Statutory damages: $1,000 per negligent violation, $5,000 per intentional/reckless violation","Illinois state court standing — distinct from federal Article III standing under Spokeo"]', '[{"section":"Holding","description":"BIPA statutory violation alone confers standing — no actual injury beyond violation required"},{"section":"Aggrieved Person","description":"Broadly defined — anyone whose statutory rights under BIPA are violated"},{"section":"Prophylactic Purpose","description":"BIPA designed to prevent harm before it occurs — actual injury requirement would defeat purpose"},{"section":"Impact","description":"Foundation for massive BIPA class action litigation — billions in potential statutory damages"}]', '["bipa_complaint","biometric_privacy_claim","class_action_bipa","consent_compliance_audit","biometric_data_collection_policy","statutory_damages_calculation"]', '["privacy-data-protection-audit"]', 'Illinois State Courts', 1, 1, datetime('now'), datetime('now'));

-- Van Buren v. United States — CFAA "Exceeds Authorized Access"
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_052', 'PRIVAXIS', 'CASE_LAW', 'US', 'Van Buren v. United States, 593 U.S. 374 (2021)', 'Van Buren v. United States', 'CFAA — "Exceeds Authorized Access" Means Accessing Off-Limits Areas, Not Misusing Authorized Access', 'Computer Fraud and Abuse Act''s "exceeds authorized access" provision covers those who obtain information from particular areas of the computer — such as files, folders, or databases — to which their computer access does not extend. It does not cover those who access information for improper purposes but from areas they are otherwise authorized to access. A police officer who ran license plate database search for personal reasons had authorized access and did not violate CFAA even though the search violated department policy. Gates-up-or-down model adopted.', '["Exceeds authorized access = accessing areas of computer that are off-limits","Does not mean misusing access to areas where access is authorized","Gates-up-or-down model: either you can access the area or you cannot","Policy-based access restrictions do not create CFAA liability","Officer running authorized database for personal purpose did not exceed access","Rejects broad interpretation that would criminalize commonplace computer activity","Narrow reading avoids making felons of millions who violate computer use policies","CFAA § 1030(e)(6): exceeds authorized access means accessing computer with authorization and using access to obtain information not entitled to obtain"]', '[{"section":"Holding","description":"Exceeds authorized access means accessing off-limits computer areas, not misusing authorized access"},{"section":"Gates Model","description":"Access is binary — either user can access the area or cannot — not dependent on purpose"},{"section":"Policy Violations","description":"Violating employer computer use policy does not create CFAA liability"},{"section":"Impact","description":"Narrowed CFAA scope — protects against overcriminalization of routine computer use policy violations"}]', '["cfaa_defense","computer_fraud_claim","authorized_access_analysis","data_breach_complaint","employee_computer_use_policy","cfaa_civil_claim"]', '["privacy-data-protection-audit"]', 'Federal Courts / DOJ', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- HOUSING DISCRIMINATION (REGULIS)
-- ═══════════════════════════════════════════════════════════════════════════

-- Fair Housing Council v. Roommates.com — CDA § 230 / FHA Online
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_053', 'REGULIS', 'CASE_LAW', 'US', 'Fair Housing Council v. Roommates.com, LLC, 521 F.3d 1157 (9th Cir. 2008)', 'Roommates.com', 'CDA § 230 Does Not Immunize Platforms Creating Discriminatory Content — FHA Applies Online', 'Communications Decency Act § 230 does not immunize online platforms that materially contribute to the alleged illegality of content. Roommates.com was not a passive conduit — it required users to disclose protected characteristics (sex, sexual orientation, family status) and used that information to channel listings. A website that creates or develops discriminatory content is an information content provider, not merely an interactive computer service immune under § 230. Fair Housing Act applies to online housing platforms. Distinction between neutral tools and those designed to facilitate discrimination.', '["CDA § 230 immunity does not protect platforms that create or develop illegal content","Material contribution to illegality removes § 230 protection","Requiring disclosure of protected characteristics is content creation, not neutral hosting","FHA prohibitions apply equally to online housing platforms","Platform that designs tools facilitating discrimination is information content provider","Neutral tools available equally to all are protected — discriminatory tools are not","§ 230 protects good-faith screening, not participation in illegality","En banc Ninth Circuit decision — influential nationwide"]', '[{"section":"Holding","description":"§ 230 does not immunize platforms that create or develop discriminatory content — FHA applies online"},{"section":"Content Creation","description":"Requiring protected characteristics and channeling listings = content creation, not passive hosting"},{"section":"Material Contribution","description":"Platform materially contributing to illegality loses § 230 immunity"},{"section":"Impact","description":"Leading authority on § 230 limits in housing discrimination — FHA enforcement extends to digital platforms"}]', '["fha_complaint","housing_discrimination_claim","section_230_defense","online_platform_compliance","content_moderation_policy","digital_housing_audit"]', '["california-housing-tenant-audit"]', 'HUD / Federal Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- FAMILY LAW (ADVOCIS)
-- ═══════════════════════════════════════════════════════════════════════════

-- In re Marriage of Burgess — Move-Away / Custodial Parent
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_case_054', 'ADVOCIS', 'CASE_LAW', 'CA', 'In re Marriage of Burgess, 13 Cal.4th 25 (1996)', 'Marriage of Burgess', 'Move-Away Rights — Custodial Parent Presumptive Right to Relocate With Child', 'Custodial parent has a presumptive right to change the residence of the child. Noncustodial parent bears the burden of showing that the proposed move would cause detriment to the child, warranting a change in custody. Court must consider the best interests of the child in light of all relevant factors. No presumption against relocation. The custodial parent''s reasons for relocating are not determinative but are relevant. Court must consider the stability and continuity of existing custody arrangement. Foundational move-away case — later supplemented by In re Marriage of LaMusga (2004) which addressed changed-circumstance threshold.', '["Custodial parent has presumptive right to change child''s residence","Noncustodial parent bears burden to show detriment warranting custody change","Best interests of child governs — all relevant factors considered","No presumption against relocation — burden is on objecting parent","Custodial parent''s reasons relevant but not determinative","Stability and continuity of existing arrangement considered","Initial custody order: best interests standard applies","Modification: changed circumstances threshold before best interests (LaMusga supplement)","Temporary restraining orders cannot prevent relocation without proper showing"]', '[{"section":"Holding","description":"Custodial parent has presumptive right to relocate — noncustodial must show detriment"},{"section":"Burden","description":"Noncustodial parent bears burden of showing move would cause detriment to child"},{"section":"Best Interests","description":"All relevant factors considered including stability, continuity, and reasons for move"},{"section":"Impact","description":"Foundational CA move-away case — supplemented by LaMusga (2004) on changed-circumstance threshold for modification"}]', '["move_away_motion","custody_modification_request","relocation_opposition","best_interests_analysis","change_of_circumstances_motion","custody_evaluation_report"]', '["family-law-custody-audit"]', 'CA Family Courts', 1, 1, datetime('now'), datetime('now'));
